[{"fieldname": "print_heading_template", "fieldtype": "Custom HTML", "options": "<div></div>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<div class="sewing-consumption-print">
    {% set data = get_sewing_consumption_print_data(doc.name) %}
    <style>
        .sewing-consumption-print { font-size: 12px; color: #111; }
        .sewing-consumption-print h2,
        .sewing-consumption-print h3 { margin: 8px 0 6px; }
        .sewing-consumption-print .meta { margin-bottom: 12px; line-height: 1.5; }
        .sewing-consumption-print table { width: 100%; border-collapse: collapse; margin-bottom: 14px; }
        .sewing-consumption-print th,
        .sewing-consumption-print td { border: 1px solid #111; padding: 4px 6px; vertical-align: top; }
        .sewing-consumption-print th { background: #f2f2f2; }
    </style>

    <h2>Sewing Consumption</h2>
    <div class="meta">
        <div><strong>Lot:</strong> {{ data.lot or '-' }}</div>
        <div><strong>IPD:</strong> {{ data.ipd or doc.name }}</div>
        <div><strong>Supplier:</strong> {{ data.supplier or '-' }}</div>
    </div>

    {% for section in data.sections or [] %}
        <h3>{{ section.item }}</h3>
        <table>
            <thead>
                <tr>
                    <th style="width: 5%;">S.No</th>
                    {% for attr in section.item_attributes or [] %}
                        <th>{{ (attr or '').split('_', 1)[1] if '_' in attr else attr }}</th>
                    {% endfor %}
                    <th style="width: 10%;">Qty</th>
                    <th style="width: 18%;">Consumption Qty</th>
                </tr>
            </thead>
            <tbody>
                {% for row in section.rows or [] %}
                    <tr>
                        <td>{{ loop.index }}</td>
                        {% for attr in section.item_attributes or [] %}
                            <td>{{ row.values.get(attr) or '-' }}</td>
                        {% endfor %}
                        <td>{{ row.item_bom_qty or 0 }}</td>
                        <td>{{ row.quantity or 0 }}</td>
                    </tr>
                {% endfor %}
            </tbody>
        </table>
    {% endfor %}

    {% for group in data.cloth_acc_data or [] %}
        <h3>Cloth Accessory Consumption{% if group.accessory_type %} - {{ group.accessory_type|join(', ') }}{% endif %}</h3>
        <table>
            <thead>
                <tr>
                    <th style="width: 5%;">S.No</th>
                    {% for attr in group.attributes or [] %}
                        <th>{{ attr }}</th>
                    {% endfor %}
                    <th style="width: 15%;">Consumption Weight</th>
                </tr>
            </thead>
            <tbody>
                {% for row in group.columns or [] %}
                    <tr>
                        <td>{{ loop.index }}</td>
                        {% for attr in group.attributes or [] %}
                            <td>{{ row.get(attr) or '-' }}</td>
                        {% endfor %}
                        <td>{{ row.get('Consumption Weight') or 0 }}</td>
                    </tr>
                {% endfor %}
            </tbody>
        </table>
    {% endfor %}
</div>"}]
